set-variable.value:
@{
                try {
                    var rb = (JObject)context.Variables["responseBody"];
                    return rb?["usage"]?["prompt_tokens"]?.Value<int>() ?? 0;
                } catch { return 0; }
            }

@{
                try {
                    var rb = (JObject)context.Variables["responseBody"];
                    return rb?["usage"]?["completion_tokens"]?.Value<int>() ?? 0;
                } catch { return 0; }
            }

@{
                try {
                    var rb = (JObject)context.Variables["responseBody"];
                    return rb?["usage"]?["total_tokens"]?.Value<int>() ?? 0;
                } catch { return 0; }
            }

@{
                try {
                    var sse = context.Variables.GetValueOrDefault<string>("sseBody", "");
                    var m = System.Text.RegularExpressions.Regex.Match(sse, @"""prompt_tokens""\s*:\s*(\d+)");
                    return m.Success ? int.Parse(m.Groups[1].Value) : 0;
                } catch { return 0; }
            }

@{
                try {
                    var sse = context.Variables.GetValueOrDefault<string>("sseBody", "");
                    var m = System.Text.RegularExpressions.Regex.Match(sse, @"""completion_tokens""\s*:\s*(\d+)");
                    return m.Success ? int.Parse(m.Groups[1].Value) : 0;
                } catch { return 0; }
            }

@{
                try {
                    var sse = context.Variables.GetValueOrDefault<string>("sseBody", "");
                    var m = System.Text.RegularExpressions.Regex.Match(sse, @"""total_tokens""\s*:\s*(\d+)");
                    return m.Success ? int.Parse(m.Groups[1].Value) : 0;
                } catch { return 0; }
            }

@{
        try {
            var p  = context.Variables.GetValueOrDefault<int>("promptTokens", 0);
            var c  = context.Variables.GetValueOrDefault<int>("completionTokens", 0);
            var pw = context.Variables.GetValueOrDefault<int>("promptTokensWeight", 1);
            var cw = context.Variables.GetValueOrDefault<int>("completionTokensWeight", 1);
            return (p * pw) + (c * cw);
        } catch { return 0; }
    }
